import java.util.Scanner;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String input = scanner.nextLine();

        // Creating a fixed size char array with size 10
        char[] buffer = new char[10];

        // Copying user input into the buffer array with proper bounds checking
        for (int i = 0; i < input.length() && i < buffer.length; i++) {
            buffer[i] = input.charAt(i);
        }

        // Printing out the contents of the buffer array
        System.out.print("Buffer content: ");
        for (char c : buffer) {
            System.out.print(c);
        }
    }
}

